"""Minimal Python-side conf access logger.

Resolves the Python call site and sends it to the JVM via Py4J.
All dedup, internal/external classification, and event emission
are handled centrally on the JVM by RuntimeConfigAccessLogger.

Two logging paths:

- **Classic PySpark** (conf.py): the caller passes ``jconf`` (the Java RuntimeConfig).
  We call ``jconf.logConfAccessFromPython(...)`` which routes through the per-session
  ``RuntimeConfigAccessLogger`` instance on that RuntimeConfig. Dedup is per-session.

- **Spark Connect** (connect/conf.py): no Java RuntimeConfig is available, so we fall
  back to a single ``PySparkRuntimeConfigAccessLogger`` Py4J bridge that maintains
  per-session ``RuntimeConfigAccessLogger`` instances internally (keyed by Connect
  session ID, with LRU eviction). Dedup is per-session.
"""

import inspect
from typing import Optional


_THIS_FILE_SUFFIX = "pyspark/databricks/instrumentation/runtime_config_access_logger.py"

# Known conf wrappers that delegate to RuntimeConfig. These frames are
# skipped during stack walk so the reported call site is the actual caller.
_KNOWN_CONF_WRAPPERS = {
    # (file_suffix, function_name)
    ("pyspark/databricks/instrumentation/instrumentation_utils.py", "wrapper"),
    ("pyspark/instrumentation_utils.py", "wrapper"),
    ("pyspark/sql/context.py", "setConf"),
    ("pyspark/sql/context.py", "getConf"),
    ("pyspark/ml/torch/distributor.py", "_get_conf"),
    ("pyspark/ml/torch/distributor.py", "_get_conf_boolean"),
    ("pyspark/pandas/config.py", "get_option"),
    ("pyspark/pandas/config.py", "set_option"),
    ("pyspark/pandas/config.py", "reset_option"),
    ("pyspark/pandas/config.py", "option_context"),
    ("pyspark/pandas/utils.py", "sql_conf"),
}

# Index by function name for fast lookup. Populated during _initialize() from
# _KNOWN_CONF_WRAPPERS plus SAFEr-delivered entries.
_WRAPPER_INDEX = {}


def _resolve_call_site() -> Optional[str]:
    """Walk the stack to find the caller's file and line number.

    1. Skip all frames from this file.
    2. Skip one frame (the RuntimeConfig method: get/set/unset/...).
    3. Skip any known conf-wrapper frames.
    """
    frame = inspect.currentframe()

    # 1. Skip all frames from this file.
    while frame is not None and frame.f_code.co_filename.endswith(_THIS_FILE_SUFFIX):
        frame = frame.f_back

    # 2. Skip one frame (the RuntimeConfig.get/set/unset/... method).
    if frame is not None:
        frame = frame.f_back

    # 3. Skip known conf wrappers.
    while frame is not None:
        func_name = frame.f_code.co_name
        suffixes = _WRAPPER_INDEX.get(func_name)
        if suffixes is None:
            break
        filename = frame.f_code.co_filename
        if not any(filename.endswith(s) for s in suffixes):
            break
        frame = frame.f_back

    if frame is None:
        return None

    return f"{frame.f_code.co_filename}:{frame.f_lineno}"


# ---------------------------------------------------------------------------
# State initialized lazily after SparkContext creation (no-op without local JVM).
# ---------------------------------------------------------------------------

# Global gate: True only after _initialize() succeeds and the JVM reports logging
# as enabled. When False, all entry points are no-ops (no Py4J, no stack walk).
_enabled = False

# PySparkRuntimeConfigAccessLogger bridge used by the Connect path. The bridge
# maintains per-session RuntimeConfigAccessLogger instances internally (keyed by
# session ID, with LRU eviction).
_connect_bridge = None


def _initialize():
    """Populate wrapper index and initialize the Py4J bridge."""
    global _enabled, _connect_bridge
    try:
        from pyspark.core.context import SparkContext
        jsc = SparkContext._active_spark_context._jsc
        python_utils = SparkContext._jvm.PythonUtils
        if not python_utils.isRuntimeConfigAccessLoggingEnabled(jsc):
            return

        additional_wrappers = python_utils.runtimeConfigAccessLoggingPythonAdditionalFramesToSkip(
            jsc)
        for file_suffix, func_name in list(_KNOWN_CONF_WRAPPERS) + list(additional_wrappers):
            _WRAPPER_INDEX.setdefault(func_name, []).append(file_suffix)

        _connect_bridge = (
            SparkContext._jvm.com.databricks.spark.util.PySparkRuntimeConfigAccessLogger()
        )
        _enabled = True
    except Exception:
        pass


def log_runtime_config_access(
    method: str, key: Optional[str], jconf=None, session_id: Optional[str] = None
) -> None:
    """Log a single config access. Called from RuntimeConfig methods.

    Args:
        method: The conf method name (get, set, unset, getAll, isModifiable).
        key: The conf key (None for getAll).
        jconf: The Java RuntimeConfig (classic path). When provided, logging goes
            through the per-session RuntimeConfigAccessLogger on that RuntimeConfig.
        session_id: Connect session ID. When provided (Connect path), the bridge
            uses a per-session logger keyed by this ID.
    """
    if not _enabled:
        return
    try:
        call_site = _resolve_call_site()
        if jconf is not None:
            # Classic path: per-session dedup via RuntimeConfig.confAccessLogger.
            jconf.logConfAccessFromPython(method, key, call_site)
        elif session_id is not None:
            # Connect path: per-session dedup via bridge's internal LRU map.
            _connect_bridge.logConfAccess(session_id, method, key, call_site)
    except Exception:
        pass


def _register_hook():
    """Register the lazy init hook. No-op for remote-only Connect clients."""
    from pyspark.core.context import SparkContext
    SparkContext._add_after_init_hook(_initialize)


_register_hook()
